p.m:
\displaystyle{\begin{aligned}
   \left(-\frac{25}{6}\right) \div (-20)
       \amp = \frac{25}{6} \div 20 \\
       \amp = \frac{25}{6} \div \frac{20}{1} \\
       \amp = \frac{25}{6} \cdot \frac{1}{20} \amp \hbox{We can simplify by dividing 25 and 20 by 5, making the numbers smaller.}\\
       \amp = \frac{5}{6}\cdot \frac{1}{4} \\
       \amp = \frac{5 \cdot 1}{6 \cdot 4} \\
       \amp = \frac{5}{24}
\end{aligned}
    }
